"""
MKT Original Language Commentary — Psalms chapters 140–146
Run: python3 scripts/zc-original-psalms-140-146.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json

Key decisions in this range:
- Ps 140:3 (ḥiddĕdû lĕšônām kĕnaḥāš) cited by Paul in Rom 3:13 as part of the
  universal sinfulness catena
- Ps 141:2: prayer mapped to temple ritual (incense + evening offering)
- Ps 142: cave psalm (superscription); ḥelqî (my portion) applied to YHWH
- Ps 143: last of the Davidic penitential psalms; v2 (no living person is righteous
  before God) undergirds Protestant justification theology; v10 rûaḥ ṭôbāh (good
  Spirit) as guide — one of the Psalter's few explicit Spirit-guidance references
- Ps 144: composite psalm borrowing heavily from Ps 18; vv3-4 nearly quote Ps 8:4-5
  but inverts the register (fragility not dignity); vv12-15 covenant-blessing catalog
- Ps 145: the only psalm titled tĕhillāh (praise) in its superscription; Hebrew acrostic;
  the nun verse is missing from MT (likely due to Amos 5:2 avoidance); v8 = Exod 34:6
- Ps 146: first of Hallelujah Quintet (146-150); v4 rûaḥ/ʾadāmāh = Genesis 2-3 reversed;
  vv7-9 the six divine acts for the vulnerable = Luke 4:18 Jesus manifesto
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 140-146 — late Davidic laments + royal psalm +
#   acrostic praise + first Hallelujah psalm. 88 verses across 7 chapters.
# CHANGE? If commentary/mkt-original/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json'));
#   [print(ch, len(d[ch])) for ch in [str(i) for i in range(140,147)]]"

PSALMS = {
  "140": {
    "1": '<p><strong>ḥallĕṣēnî yhwh mēʾādām rāʿ mēʾîš ḥămāsîm tiṣṣĕrēnî</strong> — "rescue me, O LORD, from evil men; protect me from violent men" — <em>ḥālaṣ</em> (to draw out, rescue, extricate — Piel) — originally to pull off a sandal, then extended to extracting from danger. <em>ʾîš ḥămāsîm</em> (men of violence, from <em>ḥāmās</em>, violence, wrongdoing) — <em>ḥāmās</em> is the pervasive OT word for physical and social violence that overturns right order; it is specifically what caused the Flood (Gen 6:11,13). The superscription names David, suggesting the setting of Saul\'s court or the Absalom rebellion.</p>',
    "2": '<p><strong>ʾăšer ḥāšĕbû rāʿôt bĕlēb kol-yôm yāgûrû milḥāmôt</strong> — "who scheme wickedness in their hearts and stir up conflicts every day" — <em>ḥāšab</em> (to plan, devise, calculate, reckon) — used for skilled craftsmanship (Exod 31:4) and for deliberate scheming; the same mental intensity applied to both art and malice. <em>kol-yôm</em> (every day) — the constancy of their scheming makes it structural, not occasional. <em>yāgûrû milḥāmôt</em> (they stir up / assemble wars) — <em>gûr</em> in this context = to attack, stir up strife.</p>',
    "3": '<p><strong>šānnĕnû lĕšônām kĕnaḥāš ḥămat ʿakšûb taḥat śĕpātêhem selāh</strong> — "they sharpen their tongues like a serpent; viper venom is under their lips" — <em>šānan</em> (to whet, sharpen) — the tongue as a blade being honed. The serpent (<em>nāḥāš</em>) metaphor links to the Eden narrative (Gen 3:1-5). <em>ḥămat ʿakšûb</em> (the venom of a viper/asp) — <em>ʿakšûb</em> is a species of Palestinian viper. Paul strings this verse into his universal-sinfulness catena in Rom 3:13 ("the poison of asps is under their lips"), bracketed by Ps 5:9 and Ps 10:7 — the psalmist\'s description of particular enemies becomes, in Paul\'s reading, a diagnosis of universal human fallenness.</p>',
    "4": '<p><strong>šomrēnî yhwh mîdê rāšāʿ miʾîš ḥămāsîm tiṣṣĕrēnî ʾăšer ḥāšĕbû lidĕḥôt pĕʿāmāy</strong> — "keep me, O LORD, from the clutches of the wicked; preserve me from violent men who plan to make me stumble" — <em>yād rāšāʿ</em> (the hand/power of the wicked) — <em>yād</em> as agency and power, not merely the anatomical hand. <em>ḥāšĕbû lidĕḥôt pĕʿāmāy</em> (they have planned to push aside/thrust my steps) — <em>dāḥāh</em> (to thrust, push away, throw down); <em>pĕʿāmîm</em> (steps, footfalls) — the wicked do not merely obstruct but actively plan to knock the psalmist off his feet.</p>',
    "5": '<p><strong>ṭāmĕnû gēʾîm pah lî ûḥăbālîm pārĕśû rešet lĕyad-maʿgāl môqĕšîm šātû-lî selāh</strong> — "the arrogant have hidden a trap for me and stretched out cords; they have spread a net beside my path and set snares" — <em>gēʾîm</em> (the proud, arrogant ones) as the subject of concealed trapping — pride and cunning working together. <em>pah</em> (a spring-trap, snare), <em>ḥăbālîm</em> (cords, ropes), <em>rešet</em> (net), <em>môqĕšîm</em> (snares) — four different trap-instruments in a single verse, creating the picture of a path surrounded and booby-trapped at every point. The bird-and-hunter imagery connects to Ps 124:7 and 141:9.</p>',
    "6": '<p><strong>ʾāmartî layhwāh ʾēlî ʾattāh hăqîšîbāh yhwh qôl taḥănûnāy</strong> — "I said to the LORD, \'You are my God\' — hear me, O LORD, listen to my pleas for mercy" — <em>ʾēlî ʾattāh</em> (you are my God) — the covenant confession is the foundation of the appeal. Amidst all the traps and violence, the psalmist\'s anchor is this relational identity: YHWH is my God, not merely a God. <em>taḥănûnāy</em> (my pleas for mercy, from <em>ḥānan</em>) — the petition follows from the relationship: because you are my God, hear my mercy-cry.</p>',
    "7": '<p><strong>yhwh ʾădōnāy ʿōz yĕšûʿātî sakkōtāh lĕrōʾšî bĕyôm nāšeq</strong> — "O LORD the Lord, the strength of my salvation — you have shielded my head in the day of battle" — <em>yhwh ʾădōnāy</em> (the covenant name + the sovereignty name together) — this double divine address appears in several psalms and in Hab 3:19, emphasizing both relational and sovereign dimensions. <em>ʿōz yĕšûʿātî</em> (the strength of my salvation) — YHWH as the source of saving power, not merely the One who saves. <em>sakkōtāh lĕrōʾšî</em> (you have covered/shielded my head) — <em>sākak</em> (to cover, screen, shield, as with a shield or canopy); the head as the most vulnerable target in battle.</p>',
    "8": '<p><strong>ʾal-tittēn yhwh maʾăwiyyê rāšāʿ zimĕzāmô ʾal-tāpēq yārûmû selāh</strong> — "do not give the wicked what they want, O LORD; do not let their evil plans succeed, or they will grow proud" — <em>maʾăwiyyê rāšāʿ</em> (the desires of the wicked, from <em>ʾāwāh</em>, to desire, crave) — granting the wicked their desires would validate their methods. <em>zimĕzāmô</em> (their evil scheme/device, from <em>zāmam</em>, to plan, devise, usually with evil intent). <em>yārûmû</em> (let them be exalted, they would be lifted up) — the imprecation protects cosmic order: a wicked man whose schemes succeed becomes proud, threatening the justice structure.</p>',
    "9": '<p><strong>rōʾš mĕsabbāy ʿămal śĕpātêmô yĕkhassĕmô</strong> — "let the trouble caused by the lips of those who hem me in fall back upon their own heads" — <em>rōʾš mĕsabbāy</em> (the head of those who surround me) — the leader or front person of the encirclement. <em>ʿămal śĕpātêmô</em> (the trouble/toil of their lips) — the verbal harm they have spoken. <em>yĕkhassĕmô</em> (let it cover them, engulf them, from <em>kāsāh</em>, to cover) — the words they have hurled at the psalmist should become a covering over themselves. The lex talionis logic: the trap set for another springs on the trapper.</p>',
    "10": '<p><strong>yimmōṭû ʿălêhem gĕḥālîm bāʾēš yappilēm bĕmaḥămōrôt bal-yāqûmû</strong> — "let burning coals rain down on them; let them be thrown into the fire — into pits so deep they never rise" — <em>gĕḥālîm</em> (burning coals, glowing embers) — the same image as Ps 120:4 (coals of broom wood). The imagery draws on the divine warrior arsenal (Ps 18:12-13; Isa 30:30). <em>maḥămōrôt</em> (pits, depths, from <em>ḥāmar</em>, to be red/boiling?) — deep pits or slime pits (cf. Gen 14:10 where the kings fell into asphalt pits). <em>bal-yāqûmû</em> (may they not rise) — the defeat is final.</p>',
    "11": '<p><strong>ʾîš lāšôn bal-yikkôn bāʾāreṣ ʾîš-ḥāmās rāʿ yĕṣûdennû lĕmaddĕḥēpôt</strong> — "let no slander take root in the land; may evil relentlessly pursue the violent man until he falls" — <em>ʾîš lāšôn</em> (a man of tongue/slander) — the lying tongue that opened the psalm (v1-3) here receives its verdict. <em>bal-yikkôn bāʾāreṣ</em> (let him not be established in the earth) — <em>kûn</em> (to be established, set firm) — the slander-man should have no permanent footing. <em>yĕṣûdennû lĕmaddĕḥēpôt</strong> (evil will hunt him to overthrows/downfalls) — <em>dāḥāh</em> (to push, thrust over) — the same verb as v4\'s plan to push aside the psalmist\'s steps.</p>',
    "12": '<p><strong>yādaʿtî kî-yaʿăśeh yhwh dîn ʿānî mišpaṭ ʾebyônîm</strong> — "I know that the LORD will uphold the cause of the afflicted and defend the rights of the poor" — the psalm\'s confident affirmation after the imprecations: not wishing but knowing (<em>yādaʿtî</em>, perfect tense — settled knowledge). <em>dîn ʿānî</em> (the cause/case of the afflicted) and <em>mišpaṭ ʾebyônîm</em> (the justice/right of the poor/needy) — both legal-court terms; YHWH is the judge who takes up the case of those without human advocates.</p>',
    "13": '<p><strong>ʾak ṣaddîqîm yôdû lišmĕkā yēšĕbû yĕšārîm ʾet-pānêkā</strong> — "surely the righteous will give thanks to your name; the upright will dwell in your presence" — <em>ʾak</em> (surely, only, truly) — the affirmative particle closing the psalm with confidence. <em>yōdû lišmĕkā</em> (they will give thanks/praise to your name) — <em>yādāh</em> (Hiphil, to praise, acknowledge) — the same root as <em>tôdāh</em> (thanksgiving). <em>yēšĕbû ʾet-pānêkā</em> (they will dwell in/with your presence) — the ultimate covenant blessing: dwelling with the face of YHWH (Ps 17:15; 73:23-24).</p>',
  },
  "141": {
    "1": '<p><strong>yhwh qĕrāʾtîkā ḥûšāh lî hăqîšîbāh qôlî bĕqorʾî-lāk</strong> — "O LORD, I call on you — come quickly! Hear my voice when I call to you" — <em>ḥûšāh lî</em> (make haste to/for me, hurry!) — <em>ḥûš</em> (to hasten, make speed) as an urgent imperative — the cry of someone who cannot wait. <em>hăqîšîbāh qôlî</em> (give ear to my voice) — <em>qāšab</em> (to pay attention, listen carefully, prick up the ears) — the prayer is for God\'s ears to be attuned to this specific voice in this specific moment.</p>',
    "2": '<p><strong>tikkôn tĕpillātî qĕṭōret lĕpānêkā maśśĕʾat kappay minḥat-ʿārěb</strong> — "may my prayer be set as incense before you, and the lifting of my hands as the evening offering" — <em>qĕṭōret</em> (incense, smoke of burning spices) — the incense altar in the tabernacle/temple burned morning and evening (Exod 30:7-8); the rising smoke visualized prayer ascending to YHWH. <em>maśśĕʾat kappay</em> (the lifting/raising of my palms) — the gesture of open-palmed prayer (1 Kgs 8:22, 38). <em>minḥat-ʿārěb</em> (the evening meal-offering) — the temple\'s evening grain offering; the psalmist maps his personal prayer to both the incense offering and the grain offering, making prayerless temple worship impossible (the sacrifice without the prayer is incomplete) and temple-less prayer legitimate (the prayer maps to the sacrifice).</p>',
    "3": '<p><strong>šîtāh yhwh šomrāh lĕpî nĕṣōr ʿal-delet śĕpātāy</strong> — "post a guard at my mouth, O LORD; station a sentry at the door of my lips" — the military metaphors of guarding (<em>šāmar</em>) and the door-sentry (<em>delet</em>) applied to the lips. The gate/door image frames the lips as the entrance to a fortified space: what passes through this gate must be controlled. The prayer is remarkable — the psalmist does not trust his own self-control; he asks YHWH to be the external guard of his speech. <em>nāṣar</em> (to guard, watch over, preserve — used of guarding Torah, secrets, and cities) — a guard of the highest order.</p>',
    "4": '<p><strong>ʾal-taṭ libbî lĕdābar rāʿ lĕhitʿôlēl ʿălilôt bĕrešaʿ ʾet-ʾanšê pōʿălê ʾāwen wĕbal-ʾelḥam bĕmanʿammêhem</strong> — "do not let my heart be drawn to anything evil — to take part in the wicked acts of evildoers, or to taste any of their pleasures" — <em>ʾal-taṭ libbî</em> (do not incline my heart) — <em>nāṭāh</em> (to extend, bend, incline — used for pitching a tent, stretching out a hand, inclining the ear). The heart can be "bent" toward evil; the psalmist prays for its trajectory to be controlled. <em>ʾelḥam bĕmanʿammêhem</em> (let me not eat their delicacies/pleasures) — <em>manʿammîm</em> (delicacies, pleasant things) — the temptation of complicity is framed as food: tasting the pleasures that come with wickedness.</p>',
    "5": '<p><strong>yĕhalmēnî ṣaddîq ḥesed wĕyôkîḥēnî šemen rōʾš ʾal-yānî rōʾšî</strong> — "let a righteous man strike me — it is a kindness; let him rebuke me — it is like oil on my head; let my head not refuse it" — <em>yĕhalmēnî</em> (let him strike me, beat me, Qal jussive of <em>hālam</em>) — the same verb for hammer-strikes (Judg 5:26). But the striker is <em>ṣaddîq</em> (righteous) and the striking is <em>ḥesed</em> (covenant love) — blows from a righteous friend are acts of love. <em>šemen rōʾš</em> (oil of the head) — anointing oil as welcome enrichment; the righteous man\'s rebuke is as enriching as anointing. The counterintuitive theology: honest rebuke from the righteous is to be welcomed more than the flattery of the wicked. James 5:19-20 and Prov 27:6 stand in this tradition.</p>',
    "6": '<p><strong>nišmĕṭû bîdê-selaʿ šōpĕṭêhem wĕšāmĕʿû ʾămārāy kî nāʿēmû</strong> — "when their leaders are hurled down from the cliffs, the people will find my words welcome" — <em>nišmĕṭû bîdê-selaʿ</em> (they are thrown from the rock/cliff, Niphal of <em>šāmaṭ</em>, to release, let fall, drop) — the violent end of the wicked judges. <em>šōpĕṭêhem</em> (their judges/leaders) — the ones who currently threaten the psalmist. <em>wĕšāmĕʿû ʾămārāy kî nāʿēmû</em> (then they will hear my words, for they are pleasant) — the people who ignored the psalmist\'s words under oppression will find them welcome when the oppressors fall.</p>',
    "7": '<p><strong>kĕmô pōlēaḥ ûbōqēaʿ bāʾāreṣ niprĕdû ʿăṣāmênû lĕpî šĕʾôl</strong> — "like clods of earth that are broken up and scattered, our bones lie scattered at the mouth of Sheol" — the difficult verse — the image of plowing/splitting the ground is compared to the scattered bones of the psalmist\'s companions. <em>pōlēaḥ ûbōqēaʿ</em> (splitting and cleaving) describes the plow\'s action on hard soil. <em>ʿăṣāmênû</em> (our bones) — the group has suffered such devastation that their bones are already scattered at Sheol\'s mouth. This may be the extremity of David\'s exile community rather than literal death.</p>',
    "8": '<p><strong>kî ʾēlêkā yhwh ʾădōnāy ʿênāy bĕkā ḥāsîtî ʾal-tĕʿar napšî</strong> — "but my eyes are fixed on you, O Lord GOD — in you I shelter; do not leave my soul exposed" — the pivot from the extremity of v7 to fixed gaze. <em>ʿênāy</em> (my eyes) as the directional commitment — the gaze determines the trust. <em>bĕkā ḥāsîtî</em> (in you I have taken refuge) — <em>ḥāsāh</em> (to take refuge, shelter, flee to for protection) — the classic Psalter verb for running to YHWH as one\'s safe place. <em>ʾal-tĕʿar napšî</em> (do not pour out/expose my soul) — <em>ʿārāh</em> (to lay bare, uncover, pour out) — the soul left exposed like something stripped of its protective covering.</p>',
    "9": '<p><strong>šomrēnî mîdê pah yāqĕšû-lî ûmôqĕšôt pōʿălê ʾāwen</strong> — "keep me from the trap they have set for me, and from the snares of evildoers" — <em>pah yāqĕšû-lî</em> (the trap they have laid for me) — <em>yāqaš</em> (to lay a bird-snare) — the fowler-imagery connects back to Ps 124:7 and 140:5. The path of the righteous is consistently described in these psalms as surrounded by hidden traps — requiring divine navigation to walk safely.</p>',
    "10": '<p><strong>yippĕlû bĕmakmōrāyw rĕšāʿîm yaḥad ʾānōkî ʿad-ʾeʿĕbōr</strong> — "let the wicked fall into their own nets, while I pass over safely" — <em>makmōrāyw</em> (his own nets, from <em>kāmar</em>, to ensnare) — the nets the wicked set for others become their own trap. <em>yaḥad ʾānōkî ʿad-ʾeʿĕbōr</em> (while I alone pass over safely) — <em>ʿābar</em> (to cross over, pass through, pass by) — the Passover resonance is unmistakable: the righteous "passes over" while judgment falls on others. The psalm ends with a vision of escape through the very traps the enemy set.</p>',
  },
  "142": {
    "1": '<p><strong>qôlî ʾel-yhwh ʾezʿāq qôlî ʾel-yhwh ʾetḥannān</strong> — "with full voice I cry out to the LORD; with full voice I plead with him for mercy" — the doubled <em>qôlî</em> (my voice, my voice) — emphatic: this is audible, full-throated prayer, not silent or formal. The superscription connects this to David in a cave (1 Sam 22:1, Adullam; or 1 Sam 24, En-gedi), giving it the setting of fugitive desperation. <em>ʾezʿāq</em> (I cry out, shout for help, from <em>zāʿaq</em>, the verb for the Israelites\' cry in Egypt, Exod 2:23) + <em>ʾetḥannān</em> (I plead for grace/mercy, Hithpael of <em>ḥānan</em>) — the two modes of desperate prayer: the urgent shout and the pleading for mercy.</p>',
    "2": '<p><strong>ʾešpōk lĕpānāyw śîḥî ṣārātî lĕpānāyw ʾaggîd</strong> — "I pour out my troubles before him; I lay my distress before him" — <em>ʾešpōk śîḥî</em> (I pour out my complaint/meditation, from <em>šāpak</em>, to pour out + <em>śîaḥ</em>, meditation, complaint, musing) — the liquid metaphor for prayer: what has been accumulating inside is now poured out before YHWH. <em>ṣārātî</em> (my distress, from <em>ṣārar</em>, to be in a narrow place, constrained) — the claustrophobia of being hemmed in. Both <em>śîaḥ</em> and <em>ṣārāh</em> are laid "before his face" (<em>lĕpānāyw</em>) — the face of YHWH as the place of honest presentation.</p>',
    "3": '<p><strong>bĕhiṭʿaṭṭēp ʿālay rûḥî wĕʾattāh yādaʿtā nĕtîbātî bĕʾōraḥ-zû ʾăhallēk ṭāmĕnû pah lî</strong> — "when my spirit grows faint within me, you know my path. In the path I must travel, they have hidden a trap for me" — <em>hiṭʿaṭṭēp</em> (to faint, languish, cover oneself, from <em>ʿāṭap</em>, to be faint, to cover) — the spirit collapsing over itself like someone falling unconscious. <em>yādaʿtā nĕtîbātî</em> (you know my path) — the Psalter\'s consolation: YHWH\'s knowledge is not merely informational but relational and protective. Even the hidden trap is known to him. <em>ṭāmĕnû pah lî</em> (they have hidden a trap for me) — the trap is concealed from the psalmist but not from YHWH.</p>',
    "4": '<p><strong>habbeṭ yamîn ûrĕʾēh wĕʾên-lî makkîr ʾābad mānôs mimmennî ʾên dôrēš lĕnapšî</strong> — "I look to my right and see — no one acknowledges me; all escape has perished from me; no one cares for my soul" — <em>habbeṭ yamîn ûrĕʾēh</em> (look to the right and see) — the right side was the position of the defense advocate in court (Ps 109:31; 110:5). The psalmist looks for a defender and finds none. <em>makkîr</em> (one who knows/acknowledges, from <em>nākar</em>) — no one recognizes him or admits knowing him. <em>ʾābad mānôs</em> (escape has perished/is gone) — the exit has disappeared. <em>ʾên dôrēš lĕnapšî</em> (no one is seeking [the welfare of] my soul) — in Hebrew, to "seek" someone\'s <em>nepeš</em> can mean either to inquire about their welfare or to seek their life; the phrase is deliberately ambiguous — no one seeks his good, and those who are seeking him are his enemies.</p>',
    "5": '<p><strong>zāʿaqtî ʾēlêkā yhwh ʾāmartî ʾattāh maḥsî ḥelqî bĕʾereṣ haḥayyîm</strong> — "I cry to you, O LORD; I say, \'You are my shelter and my portion in this living world\'" — <em>maḥsî</em> (my shelter, refuge, from <em>ḥāsāh</em>) — YHWH as the refuge when human advocates are absent (v4). <em>ḥelqî</em> (my portion, my share, from <em>ḥālaq</em>, to divide, to allot) — land-allotment language transferred to YHWH himself: the psalmist\'s inheritance is not land but the God who gives land. This identification (YHWH as the Levitical portion — cf. Num 18:20; Ps 73:26; Lam 3:24) removes the psalmist\'s ultimate dependence from any earthly allotment. <em>bĕʾereṣ haḥayyîm</em> (in the land of the living) — not in Sheol\'s silence but in the world where YHWH acts.</p>',
    "6": '<p><strong>haqšîbāh ʾel-rinnātî kî-dalôtî mĕʾōd haṣṣîlēnî mĕrōdĕpay kî ʾāmĕṣû mimmennî</strong> — "hear my cry, for I have been brought very low; rescue me from those who pursue me, for they are too strong for me" — <em>dalôtî mĕʾōd</em> (I am very low/reduced, Qal perfect of <em>dālal</em>, to hang low, be reduced, to be thin, impoverished) — complete depletion. <em>rōdĕpay</em> (my pursuers, from <em>rādap</em>, to pursue, chase, persecute) — the same verb for Saul pursuing David. <em>ʾāmĕṣû mimmennî</em> (they are stronger than I am) — the honest admission of being outmatched; the prayer is precisely because the psalmist cannot save himself.</p>',
    "7": '<p><strong>hôṣîʾāh mimmaskēr napšî lĕhôdôt ʾet-šimĕkā bî yakkĕtrû ṣaddîqîm kî tigmōl ʿālay</strong> — "lead my soul out of this prison so I can praise your name; then the righteous will gather around me, because you will have been generous to me" — <em>mimmaskēr</em> (from the prison/enclosure, from <em>sākar</em>, to shut, enclose) — the cave of v1\'s superscription becomes the prison. <em>lĕhôdôt ʾet-šimĕkā</em> (to praise/acknowledge your name) — the motivation for rescue is worship: the dead cannot praise (Ps 115:17), so rescue enables the very thing YHWH desires. <em>bî yakkĕtrû ṣaddîqîm</em> (the righteous will crown/encircle themselves around me) — <em>kātar</em> (to surround, encircle, crown) — community restored around the delivered one. <em>kî tigmōl ʿālay</em> (because you will have been generous/will have dealt fully with me) — <em>gāmal</em> (to deal fully, recompense, wean) — the generous divine dealing becomes the rallying point of the community.</p>',
  },
  "143": {
    "1": '<p><strong>yhwh šĕmaʿ tĕpillātî haʾăzînāh ʾel-taḥănûnāy baʾămûnātĕkā ʿănēnî bĕṣidqātĕkā</strong> — "O LORD, hear my prayer; listen to my pleas for mercy; in your faithfulness and righteousness, answer me" — the appeal grounds YHWH\'s response not in the psalmist\'s merit but in two divine attributes: <em>ʾĕmûnāh</em> (faithfulness, reliability, from <em>ʾāman</em> — the root of <em>ʾāmēn</em>) and <em>ṣĕdāqāh</em> (righteousness, right action). The psalmist appeals to YHWH\'s character rather than to his own deserving — a structurally important opening that anticipates v2\'s disclaimer of personal righteousness.</p>',
    "2": '<p><strong>wĕʾal-tābôʾ bĕmišpāṭ ʾet-ʿabdĕkā kî lōʾ-yiṣdaq lĕpānêkā kol-ḥāy</strong> — "do not bring your servant into judgment, for no living person can stand as righteous before you" — <em>ʾal-tābôʾ bĕmišpāṭ</em> (do not enter into judgment with) — if YHWH were to mount a full judicial review of the servant\'s life, the verdict would be fatal. <em>lōʾ-yiṣdaq lĕpānêkā kol-ḥāy</em> (no living person can be declared righteous before you) — one of the OT\'s most unambiguous statements of universal human moral inadequacy before the divine standard. This verse stands behind the NT\'s doctrine of justification by grace: if no one is righteous before God (cf. Rom 3:20, Gal 2:16 — Paul cites Ps 143:2 directly), then the only hope is God\'s own provision of righteousness. The verse is cited without modification in the Greek of Gal 2:16.</p>',
    "3": '<p><strong>kî rādap ʾôyēb napšî dikkāʾ lāʾāreṣ ḥayyātî hôšîbanî bĕmahăšakkîm kĕmētê ʿôlām</strong> — "for the enemy has hunted me down and crushed my life to the ground; he has forced me to dwell in darkness like those who died long ago" — <em>dikkāʾ lāʾāreṣ ḥayyātî</em> (he crushed my life to the ground) — <em>dākaʾ</em> (to crush, smite, contrite — related to <em>dakkāʾ</em>, the crushed/contrite ones of Ps 51:17; Isa 57:15). <em>mahăšakkîm</em> (dark places, from <em>ḥāšak</em>, to be dark) — the places of darkness equivalent to Sheol. <em>kĕmētê ʿôlām</em> (like those who died long ago, the long-dead ones) — the psalmist is still alive but already experiencing the condition of the permanently dead.</p>',
    "4": '<p><strong>waṭṭitʿaṭṭēp ʿālay rûḥî bĕtôkî yiššōmēm libbî</strong> — "so my spirit grows faint within me; my heart within me is filled with dismay/is appalled" — <em>hiṭʿaṭṭēp rûḥî</em> (my spirit faints/collapses, same verb as Ps 142:3) — the two cave/darkness psalms (142-143) share this vocabulary of spiritual collapse. <em>yiššōmēm libbî</em> (my heart is desolate/appalled, Hithpael of <em>šāmam</em>, to be desolate, devastated, appalled) — the word used for desolated land after catastrophe (Lam 1:13,16); the heart is a desolated landscape.</p>',
    "5": '<p><strong>zākartî yāmîm miqqedem hāgîtî bĕkhol-paʿălĕkā bĕmaʿăśēh yādêkā ʾăśôḥēaḥ</strong> — "I call to mind the days of old; I meditate on all you have done; I reflect on the work of your hands" — <em>zākartî yāmîm miqqedem</em> (I remember the days of old) — the classic Deuteronomic move: when the present is overwhelming, look back to what YHWH has done in history. <em>hāgîtî</em> (I meditate, murmur, from <em>hāgāh</em> — the same verb as Ps 1:2\'s Torah-meditation). <em>ʾăśôḥēaḥ</em> (I reflect, muse, from <em>śîaḥ</em> — complaint/meditation, the same word as Ps 142:2) — here the musing is turned from complaint to contemplation of YHWH\'s past works.</p>',
    "6": '<p><strong>pēraśtî yādāy ʾēlêkā napšî kĕʾereṣ ʿăyēpāh lĕkā selāh</strong> — "I reach out my hands toward you; my whole being longs for you like a parched land" — <em>pēraśtî yādāy ʾēlêkā</em> (I spread out my hands toward you) — the gesture of open-palmed prayer extending toward YHWH. <em>napšî kĕʾereṣ ʿăyēpāh lĕkā</em> (my soul is like a parched/thirsty land to/for you) — one of the Psalter\'s most vivid anthropological images: the whole living person (<em>nepeš</em>) is a dried, cracked landscape yearning for rain. The simile maps onto the agricultural reality of the Judean wilderness — soil that has split open from thirst literally gapes open seeking water. The soul\'s orientation toward YHWH is structural, like the cracked earth\'s openness to rain.</p>',
    "7": '<p><strong>mahēr ʿănēnî yhwh kālĕtāh rûḥî ʾal-tastēr pānêkā mimmennî wĕnimšaltî ʿim-yōrĕdê bôr</strong> — "answer me quickly, O LORD — my spirit is failing! Do not hide your face from me, or I will be like those who sink into the pit" — <em>kālĕtāh rûḥî</em> (my spirit is finished/consumed, from <em>kālāh</em>, to be complete, finished, consumed) — the spirit running out like a candle nearly burned through. <em>ʾal-tastēr pānêkā</em> (do not hide your face) — the hidden face of YHWH as abandonment (Ps 27:9; 88:14; Isa 54:8); the presence of YHWH\'s face is the prerequisite for life. <em>yōrĕdê bôr</em> (those who go down to the pit) — <em>bôr</em> (a pit, cistern, also Sheol) — the alternative to YHWH\'s face is being like the dead.</p>',
    "8": '<p><strong>hašmîʿēnî babboqer ḥasdĕkā kî-bĕkā bāṭāḥtî hôdîʿēnî derekh-zû ʾēlēk kî-ʾēlêkā nāśāʾtî napšî</strong> — "let me hear of your steadfast love in the morning, for in you I put my trust; show me the path I should take, for I lift my soul to you" — <em>hašmîʿēnî babboqer</em> (cause me to hear in the morning) — morning as the traditional time of divine salvation announcement (Ps 46:5: "God will help her at the break of dawn"; 90:14; Lam 3:23). The morning announcement of <em>ḥesed</em> (covenant love) answers the night of darkness (v3). <em>derekh-zû ʾēlēk</em> (the path by which I should go) — practical directional guidance embedded within the deep prayer for covenant love.</p>',
    "9": '<p><strong>haṣṣîlēnî mēʾōyĕbay yhwh ʾēlêkā kissîtî</strong> — "rescue me from my enemies, O LORD — I run to you for shelter" — <em>kissîtî</em> (I have covered/hidden myself, from <em>kāsāh</em>, to cover) — the psalmist uses YHWH as a covering, a hiding place (Ps 32:7; 91:1-4). The phrase may also be read "to you I have fled for cover" — YHWH as the protective hiding place from enemy pursuit.</p>',
    "10": '<p><strong>lammĕdēnî laʿăśôt rĕṣônĕkā kî-ʾattāh ʾĕlōhāy rûḥăkā ṭôbāh tanhênî bĕʾereṣ mîšôr</strong> — "teach me to do your will, for you are my God; may your good Spirit lead me on a level path" — <em>rûḥăkā ṭôbāh</em> (your good Spirit) — one of only three explicit references to the divine Spirit in the Psalter (Ps 51:11: "take not your Holy Spirit from me"; Ps 139:7: "where shall I flee from your Spirit?"; here). <em>ṭôbāh</em> (good, pleasant, beneficent) distinguishes this from a merely powerful or ambiguous spirit. <em>tanhênî bĕʾereṣ mîšôr</em> (lead me on a level/smooth path, from <em>nāḥāh</em>, to lead + <em>mîšôr</em>, level ground, plain, straightness) — the Spirit\'s leading counteracts the rough, trap-laden terrain of the enemy\'s path (vv3-4). The Spirit levels the road for the psalmist\'s walk.</p>',
    "11": '<p><strong>lĕmaʿan-šimĕkā yhwh tĕḥayyēnî bĕṣidqātĕkā tôṣîʾ miṣṣārāh napšî</strong> — "for the sake of your name, O LORD, keep me alive; in your righteousness lead my soul out of its distress" — <em>lĕmaʿan-šimĕkā</em> (for the sake of your name) — the appeal to YHWH\'s own reputation rather than to the psalmist\'s merit (cf. Ps 25:11; 31:3; Ezek 36:22). YHWH\'s life-preserving action demonstrates who he is. <em>bĕṣidqātĕkā</em> (in your righteousness) — righteousness not as judgment (as it could be in v2\'s legal setting) but as salvific activity: the righteous God acts righteously by saving the one who cries to him.</p>',
    "12": '<p><strong>ûbĕḥasdĕkā taṣmît ʾôyĕbāy wĕhʾăbadtā kol-ṣōrĕrê napšî kî ʾănî ʿabdĕkā</strong> — "and in your steadfast love silence my enemies and put an end to all who oppress me — for I am your servant" — <em>ûbĕḥasdĕkā</em> (in your ḥesed) — the psalm closes as it opened: both the appeal and the action are grounded in divine character attributes (<em>ʾĕmûnāh</em> and <em>ṣĕdāqāh</em>, v1; <em>ḥesed</em>, v12). <em>kî ʾănî ʿabdĕkā</em> (for I am your servant) — the final self-identification; the claim is not moral excellence but covenantal relationship: the servant has recourse to the master. Ps 143 moves from universal human inadequacy (v2) to the servant\'s particular claim on the master\'s <em>ḥesed</em> (v12).</p>',
  },
  "144": {
    "1": '<p><strong>bārûk yhwh ṣûrî hamĕlammēd yādāy laqrāb ʾeṣbĕʿôtāy lammilḥāmāh</strong> — "blessed is the LORD, my rock, who trains my hands for war and my fingers for battle" — <em>ṣûrî</em> (my rock) — the divine epithet <em>ṣûr</em> (rock, cliff-face) emphasizes permanence and refuge (Ps 18:2; 19:14; 28:1). The psalm borrows heavily from Ps 18 — vv1-2 closely parallel Ps 18:2,34,47. <em>hamĕlammēd yādāy laqrāb</em> (who trains my hands for war) — the divine instructor of military skill: God himself is the one who makes David effective in battle. <em>ʾeṣbĕʿôtāy lammilḥāmāh</em> (my fingers for battle) — the detail of fingers alongside hands suggests precision skill (archery, swordsmanship) rather than mere brute strength.</p>',
    "2": '<p><strong>ḥasdî ûmĕṣûdātî miśgabbî ûmĕpallĕṭî lî māginnî ûbô ḥāsîtî hārôdēd ʿammî taḥtāy</strong> — "he is my steadfast love and my fortress, my high tower and my deliverer, my shield and the one in whom I trust, who subdues peoples under me" — six divine titles stacked in rapid sequence: <em>ḥasdî</em> (my steadfast love / the source of my ḥesed), <em>mĕṣûdātî</em> (my stronghold/fortress), <em>miśgabbî</em> (my high place/refuge, from <em>śāgab</em>, to be high), <em>mĕpallĕṭî</em> (my deliverer), <em>māginnî</em> (my shield), and the one in whom I take refuge. The accumulation emphasizes that YHWH covers every dimension of protection — offensive, defensive, personal, and political.</p>',
    "3": '<p><strong>yhwh mah-ʾādām wattēdāʿēhû ben-ʾĕnôš wattaḥaššĕbēhû</strong> — "LORD, what is a human being that you take notice of him, or the son of man that you think of him?" — near-verbatim parallel to Ps 8:4 (where the same question appears: <em>mah-ʾĕnôš kî-tizkĕrennû ûben-ʾādām kî tipqĕdennû</em>). But the registers differ: Ps 8 marvels at human dignity (the human is crowned with glory despite being small); Ps 144 marvels at divine attention to such an insubstantial creature (v4 explains why the question is shocking — humans are mere breath and shadow). Heb 2:6-8 cites Ps 8:4 and applies it to Christ; Ps 144\'s darker register of human transience is the foil that makes divine attention all the more remarkable.</p>',
    "4": '<p><strong>ʾādām lahebel dāmāh yāmāyw kĕṣel ʿôbēr</strong> — "a human being is like a breath/vapor; his days pass like a shadow" — <em>hebel</em> (breath, vapor, vanity, futility) — the signature word of Ecclesiastes (Eccl 1:2: <em>hebel hăbālîm</em>, "vanity of vanities"); here applied to human existence itself. <em>kĕṣel ʿôbēr</em> (like a shadow passing) — the <em>ṣēl</em> (shadow) is the same word as YHWH\'s shade in Ps 121:5; here the insubstantial human shadow passes quickly. The theological point: because humans are so insubstantial, YHWH\'s attention to them is extraordinary condescension — yet he notices and cares (v3).</p>',
    "5": '<p><strong>yhwh haṭ-šāmêkā wĕrēd gaʿ behārîm wĕyeʿăšānû</strong> — "bow your heavens, LORD, and come down; touch the mountains so that they smoke" — <em>haṭ-šāmêkā wĕrēd</em> (bow your heavens and come down) — the Sinai theophany vocabulary: YHWH descending in cloud, fire, and earthquake (Exod 19:18; Ps 18:9). <em>gaʿ behārîm wĕyeʿăšānû</em> (touch the mountains and they will smoke) — volcanic-theophany imagery; YHWH\'s mere touch causes mountains to smoke (Ps 104:32). The psalmist petitions for a repetition of the Exodus theophany, YHWH coming down into the present crisis.</p>',
    "6": '<p><strong>bĕrôq bārāq ûtĕpîṣēm šelaḥ ḥiṣṣêkā ûtĕhummēm</strong> — "send out lightning and scatter them; shoot your arrows and put them to flight" — <em>bĕrôq bārāq</em> (flash lightning and scatter) — divine lightning as arrows (Ps 18:14; 77:17-18). <em>šelaḥ ḥiṣṣêkā ûtĕhummēm</em> (shoot your arrows and throw them into confusion) — <em>hāmam</em> (to confuse, rout, throw into panic) — the verb used for YHWH confusing the Egyptian army at the Red Sea (Exod 14:24). The petition is for YHWH to act as he did at the Exodus.</p>',
    "7": '<p><strong>šĕlaḥ yādêkā mimmārôm pĕṣēnî wĕhaṣṣîlēnî mimmayim rabbîm miyyad bĕnê nēkār</strong> — "reach down your hand from above; rescue me and deliver me from the overwhelming waters, from the hand of foreigners" — <em>šelaḥ yādêkā mimmārôm</em> (send your hand from on high) — YHWH\'s hand reaching down from the heavens. <em>mayim rabbîm</em> (the great/overwhelming waters) — the primordial chaos waters (Ps 18:16; 93:4) as the image of the enemies\' power. <em>bĕnê nēkār</strong> (sons of foreignness, foreign people) — those outside the covenant, characteristically faithless to YHWH (v8\'s characterization follows).</p>',
    "8": '<p><strong>ʾăšer pîhem dibbĕr-šāwĕʾ wîmînām yĕmîn šāqer</strong> — "whose mouths speak emptiness and whose right hand is a hand of deception" — <em>šāwĕʾ</em> (emptiness, vanity, nothingness, falsehood) — the same word as the third commandment (Exod 20:7: do not take the name of the LORD in vain/<em>šāwĕʾ</em>). Their speech is structurally empty, not merely accidentally false. <em>yĕmîn šāqer</em> (a right hand of deception) — the right hand used for oaths; a deceptive right hand is a perjured oath-hand. The foreigners are characterized by false speech and false oath — the opposite of YHWH whose word is <em>ʾĕmet</em> (truth) and whose oath is sure.</p>',
    "9": '<p><strong>ʾĕlōhîm šîr ḥādāš ʾāšîr lĕkā bĕnēbel ʿāśôr ʾăzammĕrāh-llāk</strong> — "I will sing a new song to you, O God; on a ten-stringed instrument I will sing your praise" — <em>šîr ḥādāš</em> (new song) — the same formula as Ps 33:3; 96:1; 98:1; 149:1; Isa 42:10; Rev 5:9; 14:3. A new song for a new act of divine salvation; the expected rescue (vv5-7) calls forth praise before it fully arrives. <em>nēbel ʿāśôr</em> (a ten-stringed lute/harp) — a specific instrument (Ps 33:2; 92:3), possibly with ten strings arranged in a specific tuning.</p>',
    "10": '<p><strong>hannôtēn tĕšûʿāh lammĕlākhîm hampoṣeh ʾet-dāwid ʿabdô mēḥereb rāʿāh</strong> — "who gives victory to kings and rescues his servant David from the deadly sword" — <em>hannôtēn tĕšûʿāh lammĕlākhîm</em> (the one who gives victory/salvation to kings) — YHWH as the source of royal military victory; the king\'s success is not his own but YHWH\'s gift. <em>dāwid ʿabdô</em> (his servant David) — naming David explicitly in the body of the psalm alongside "kings" in general places David within a broader theology of divine royal protection.</p>',
    "11": '<p><strong>pĕṣēnî wĕhaṣṣîlēnî miyyad-bĕnê nēkār ʾăšer pîhem dibbĕr-šāwĕʾ wîmînām yĕmîn šāqer</strong> — nearly verbatim repetition of vv7b-8. The repetition creates a refrain-structure: rescue petition (v7) + enemy characterization (v8) → new song (v9-10) → rescue petition + enemy characterization (v11) → covenant blessing vision (vv12-15). The refrain about the foreigners\' empty speech and false oath frames the covenant-blessing section as the content that is true, in contrast to the foreigners\' falseness.</p>',
    "12": '<p><strong>ʾăšer bānênû kĕnĕṭîʿîm mĕguddalîm binĕʿûrêhem bĕnôtênû kĕzāwiyyōt mĕḥuṭṭābôt tabbĕnît hêkāl</strong> — "may our sons be like vigorous plants in their youth; may our daughters be like carved corner pillars of a palace" — <em>kĕnĕṭîʿîm mĕguddalîm</em> (like plants nurtured/grown large) — the agricultural growth metaphor for human flourishing (Ps 128:3). <em>kĕzāwiyyōt mĕḥuṭṭābôt tabbĕnît hêkāl</em> (like corner pillars carved after the pattern of a palace/temple) — <em>zāwiyyōt</em> (corner pillars, angles) — the daughters are compared to architectural caryatids or atlantes, the carved human-figure columns that supported ancient temple porticoes. The comparison is one of strength, beauty, and load-bearing function — daughters who hold up the household.</p>',
    "13": '<p><strong>mĕzāwênû mĕlēʾîm mĕpîqîm mizzan ʾel-zan ṣōʾnênû maalîpôt mĕrubbābôt bĕḥûṣôtênû</strong> — "may our storehouses be full with every kind of supply; may our flocks produce thousands and ten thousands in our open country" — the covenant blessing catalog: <em>mĕzāwênû mĕlēʾîm</em> (our storehouses/granaries full) — the grain that represents security. <em>maalîpôt mĕrubbābôt</em> (producing in the ten thousands, from <em>ʾālap</em>, thousand, and <em>rābāh</em>, to be many) — the exponential multiplication of flocks echoes the Deuteronomic blessings of Deut 28:4-5 ("the increase of your livestock").</p>',
    "14": '<p><strong>ʾallûpênû mĕsubbālîm ʾên-pereṣ wĕʾên yôṣēʾt wĕʾên ṣĕwāḥāh birhōbōtênû</strong> — "may our cattle be well-laden/strong for labor; may there be no breach and no going out, no cry of distress in our streets" — <em>mĕsubbālîm</em> (laden, carrying loads, from <em>sābal</em>, to carry a heavy load) — work-cattle able to bear their loads. <em>ʾên-pereṣ</em> (no breach in the wall) — a broken-through city wall signals military defeat and exile. <em>wĕʾên yôṣēʾt</em> (no going out, no exile) — citizens not being taken captive. <em>ʾên ṣĕwāḥāh birhōbōtênû</em> (no cry of distress in our streets) — the broad street (<em>rĕḥôb</em>) is the public space where distress becomes visible and audible; its silence signals peace.</p>',
    "15": '<p><strong>ʾašrê hāʿām šekkākāh llô ʾašrê hāʿām šeyhwāh ʾĕlōhāyw</strong> — "blessed are the people for whom it is so; blessed are the people whose God is the LORD" — the double beatitude closes the covenant-blessing section. <em>šekkākāh llô</em> (for whom it is so, lit. "that it is thus to him") — the material blessings of vv12-14. <em>ʾašrê hāʿām šeyhwāh ʾĕlōhāyw</em> (blessed are the people whose God is the LORD) — the second beatitude deepens the first: the real blessing is not the material catalog but the relationship with YHWH that generates it. A people whose God is the LORD have the source of blessing, not merely its expressions.</p>',
  },
  "145": {
    "1": '<p><strong>tĕhillāh lĕdāwid ʾărômimĕkā ʾĕlôhay hammĕlek ʾăbārĕkāh šimĕkā lĕʿôlām wāʿed</strong> — "a praise of David: I will exalt you, my God and King, and bless your name forever and ever" — the superscription <em>tĕhillāh lĕdāwid</em> (a praise of David) — uniquely among the Psalms, Ps 145 is the only one explicitly titled a <em>tĕhillāh</em> (praise, from <em>hālal</em>). In rabbinic Judaism this became the <em>Ashrei</em> psalm, recited three times daily. Ps 145 is a Hebrew acrostic — each verse begins with successive letters (aleph through taw, with the nun letter missing in the MT — probably due to Amos 5:2\'s use of the nāpĕlāh [fallen] for Israel). <em>ʾĕlôhay hammĕlek</em> (my God and King) — dual title: relational (<em>ʾĕlôhay</em>, my God) and royal (<em>mĕlek</em>, king). YHWH is both covenant partner and sovereign.</p>',
    "2": '<p><strong>bĕkhol-yôm ʾăbārĕkekā waʾăhallĕlāh šimĕkā lĕʿôlām wāʿed</strong> — "every day I will bless you and praise your name forever and ever" — <em>bĕkhol-yôm</em> (every day) — the daily rhythm of blessing: not annual or occasional but quotidian. The temporal markers expand: <em>bĕkhol-yôm</em> (every day) + <em>lĕʿôlām wāʿed</em> (forever and ever). Praise as the fundamental orientation of each day within an eternal horizon. The three-times-daily recitation in Judaism embodies precisely this daily rhythm.</p>',
    "3": '<p><strong>gādôl yhwh ûmĕhullāl mĕʾōd wĕligdullātô ʾên ḥēqer</strong> — "the LORD is great and highly to be praised; his greatness no one can search out" — <em>gādôl yhwh ûmĕhullāl mĕʾōd</em> (the LORD is great and greatly to be praised) — the pairing of greatness and praise-worthiness: the magnitude of YHWH is the very ground of praise. <em>ligdullātô ʾên ḥēqer</em> (his greatness has no searching out/fathoming) — <em>ḥēqer</em> (searching, investigation, from <em>ḥāqar</em>, to search out, examine) — YHWH\'s greatness is incomprehensible, beyond the reach of investigation. The Psalter\'s "great" psalms make this claim repeatedly (Ps 48:1; 95:3).</p>',
    "4": '<p><strong>dôr lĕdôr yĕšabbaḥ maʿăśêkā ûgĕbûrōtêkā yaggîdû</strong> — "one generation will commend your works to the next and will tell of your mighty deeds" — <em>dôr lĕdôr</em> (generation to generation) — the intergenerational transmission of praise is both historical continuity and theological necessity: the works of YHWH must be passed on, or they are forgotten. <em>yĕšabbaḥ maʿăśêkā</em> (they will laud/praise your works, from <em>šābaḥ</em>, to praise, commend — the same verb as Ps 117:1) — the emphasis on works and deeds (<em>maʿăśêkā</em>, <em>gĕbûrôt</em>) grounds the praise in history, not merely in abstract attribute.</p>',
    "5": '<p><strong>hădar kĕbôd hôdĕkā wĕdibrê nipĕlĕʾōtêkā ʾāśîḥāh</strong> — "I will speak of the splendor of your glorious majesty and of your wonderful deeds" — <em>hădār kĕbôd hôd</em> (splendor, glory, majesty) — three overlapping words for divine magnificence; the Psalter uses such pileups to gesture toward what language cannot fully capture. <em>nipĕlĕʾōtêkā</em> (your wonderful deeds, from <em>pālaʾ</em>, to be extraordinary, beyond what is possible) — the <em>pĕlāʾîm</em> (wonders) are by definition things that transcend human capacity and expectation.</p>',
    "6": '<p><strong>wĕʿezûz nôrĕʾōtêkā yōʾmērû ûgĕdullātĕkā ʾăsapĕrennāh</strong> — "people will tell of the power of your awe-inspiring acts, and I will declare your greatness" — <em>nôrĕʾōtêkā</em> (your awesome/fearsome acts, Niphal participle of <em>yārēʾ</em>, to fear) — divine actions that inspire awe and fear. The structure alternates between communal proclamation ("they will say," "people will tell") and personal testimony ("I will speak," "I will declare") — the communal and individual voices of praise interwoven throughout Ps 145.</p>',
    "7": '<p><strong>zēker rab-ṭûbĕkā yabbîʿû wĕṣidqātĕkā yĕrannēnû</strong> — "they will overflow with praise for your great goodness and sing aloud of your righteousness" — <em>yabbîʿû</em> (they will pour out, bubble up, gush, from <em>nābaʿ</em>, to spring up, bubble forth) — praise as a spring that wells up and overflows, not a managed flow. <em>rab-ṭûbĕkā</em> (the abundance of your goodness) — <em>ṭûb</em> (goodness, beauty, prosperity) combined with <em>rab</em> (abundance, greatness). The pairing of <em>ṭûb</em> (goodness) and <em>ṣĕdāqāh</em> (righteousness) is characteristic of the Psalter\'s theology: YHWH\'s goodness is not separate from his right-ordering of all things.</p>',
    "8": '<p><strong>ḥannûn wĕraḥûm yhwh ʾerek ʾappayim ûgĕdal-ḥāsed</strong> — "the LORD is gracious and compassionate, slow to anger and great in steadfast love" — verbatim reproduction of Exod 34:6, the divine self-disclosure at Sinai after the golden calf. This verse is the most-quoted passage in the entire Psalter (Ps 86:15; 103:8; 111:4; 112:4; 116:5; Neh 9:17; Jon 4:2; Joel 2:13) — each time it appears it carries the full weight of the Sinai revelation. In context, Ps 145 is specifically citing this tradition: YHWH\'s rule as king (vv1-2) is characterized by the covenant attributes of grace, compassion, patience, and abundant love.</p>',
    "9": '<p><strong>ṭôb-yhwh lakkōl wĕraḥămāyw ʿal-kol-maʿăśāyw</strong> — "the LORD is good to all; his compassion extends over all he has made" — <em>ṭôb-yhwh lakkōl</em> (the LORD is good to all/everything) — the universal scope is striking: not just to Israel, not just to humans, but to all. <em>wĕraḥămāyw ʿal-kol-maʿăśāyw</em> (his compassion/tender mercies over all his works) — <em>raḥămîm</em> (plural of <em>reḥem</em>, womb-compassion) extends over the entire created order. This verse is the theological ground of the later description (v15-16) of YHWH feeding all living things.</p>',
    "10": '<p><strong>yôdûkā yhwh kol-maʿăśêkā waḥăsîdêkā yĕbārĕkûkāh</strong> — "all your works will praise you, LORD, and your devoted ones will bless you" — the created order as the sphere of universal praise (anticipated in v9\'s universal compassion). <em>kol-maʿăśêkā</em> (all your works) — all creation as praise-community. <em>ḥăsîdêkā</em> (your devoted/faithful ones, from <em>ḥesed</em>) — within the universal praise-community, Israel\'s <em>ḥăsîdîm</em> are the explicit speaking/blessing subgroup. The distinction: creation praises implicitly by its existence; the covenant people bless explicitly by their speech.</p>',
    "11": '<p><strong>kĕbôd malkûtĕkā yōʾmērû ûgĕbûrātĕkā yĕdabbērû</strong> — "they will speak of the glory of your kingdom and tell of your power" — the kingdom (<em>malkût</em>) theme begins here and runs through v13. <em>kĕbôd malkût</em> (the glory of the kingdom) — both YHWH\'s intrinsic glory and the manifestation of that glory in his royal rule. <em>gĕbûrāh</em> (power, strength, might) — the power exercised in royal action.</p>',
    "12": '<p><strong>lĕhôdîaʿ libnê hāʾādām gĕbûrōtāyw ûkĕbôd hădār malkûtô</strong> — "to make known to all humanity your mighty deeds and the majestic glory of your kingdom" — <em>libnê hāʾādām</em> (to the sons of Adam/humanity) — the witness extends beyond Israel to all human beings; the <em>ḥăsîdîm</em>\'s testimony serves a universal communicative purpose. The psalmist\'s praise is not merely self-edifying but outward-facing: making known (<em>hôdîaʿ</em>, Hiphil of <em>yādaʿ</em>) the nature of YHWH\'s kingdom to those who do not yet know it.</p>',
    "13": '<p><strong>malkûtĕkā malkût kol-ʿōlāmîm ûmemšaltĕkā bĕkhol-dôr wādôr</strong> — "your kingdom is an everlasting kingdom, and your dominion endures through all generations" — <em>malkût kol-ʿōlāmîm</em> (kingdom of all ages, lit. "kingship of all eternities") — the plural <em>ʿōlāmîm</em> emphasizes the absolute temporal scope. <em>ûmemšaltĕkā</em> (your dominion, from <em>māšal</em>, to rule) — royal authority persisting through every generation. This verse is cited in the doxology of the Lord\'s Prayer ("thine is the kingdom" — though the doxology is a later addition) and directly echoed in Dan 4:3,34 (even the Gentile king Nebuchadnezzar confesses YHWH\'s eternal kingdom).</p>',
    "14": '<p><strong>sômēk yhwh lĕkhol-hannōpĕlîm wĕzôqēp lĕkhol-hakkĕpûpîm</strong> — "the LORD upholds all who are falling and lifts up all who are bowed down" — <em>sômēk</em> (the one who supports, upholds, from <em>sāmak</em>, to lean on, support, prop — the same root as Ps 111:8, 112:8) — YHWH as the structural support for those who would otherwise fall. <em>hannōpĕlîm</em> (those who are falling, from <em>nāpal</em>, to fall) — catching them in the act of falling. <em>hakkĕpûpîm</em> (those who are bowed down, bent double, from <em>kāpap</em>, to bend, bow) — those doubled over under a load. The verse is both physical (the fallen, the stooped) and social/spiritual (the crushed, the humbled).</p>',
    "15": '<p><strong>ʿênê-khōl ʾēlêkā yĕśabbērû wĕʾattāh nôtēn-lāhem ʾet-ʾoklām bĕʿittô</strong> — "the eyes of all look to you, and you give them their food in due season" — <em>ʿênê-khōl ʾēlêkā yĕśabbērû</em> (the eyes of all are hoping toward you) — <em>śābar</em> (to wait, hope, expect) — the same expectancy as Ps 130:5\'s <em>qāwāh</em>. All creation is in a posture of expectant looking. <em>bĕʿittô</em> (in its time, in due season) — YHWH\'s provision is timed: not random or capricious but ordered to the rhythm of need.</p>',
    "16": '<p><strong>pôtēaḥ ʾet-yādĕkā ûmaśbîaʿ lĕkhol-ḥay rāṣôn</strong> — "you open your hand and satisfy the desire of every living thing" — <em>pôtēaḥ ʾet-yādĕkā</em> (you open your hand) — the open hand of YHWH as the gesture of giving; the image condenses the entire theology of divine provision. <em>ûmaśbîaʿ lĕkhol-ḥay rāṣôn</em> (and satisfy the desire of every living thing) — <em>rāṣôn</em> (desire, pleasure, goodwill, delight) — not merely the physical need but the full desire of the creature. Every living thing (<em>kol-ḥay</em>) — the scope is universal: not just humans, not just Israel, but all life.</p>',
    "17": '<p><strong>ṣaddîq yhwh bĕkhol-dĕrākhāyw wĕḥāsîd bĕkhol-maʿăśāyw</strong> — "the LORD is righteous in all his ways and faithful/loving in all his works" — <em>ṣaddîq</em> (righteous) + <em>ḥāsîd</em> (faithful, devoted, characterized by <em>ḥesed</em>) — the two attributes cover YHWH\'s moral alignment (righteousness) and his relational fidelity (ḥesed). <em>bĕkhol-dĕrākhāyw</em> (in all his ways) + <em>bĕkhol-maʿăśāyw</em> (in all his works) — the paired "all" is emphatic: no exception to righteousness or fidelity in any of YHWH\'s paths or acts.</p>',
    "18": '<p><strong>qārôb yhwh lĕkhol-qōrĕʾāyw lĕkhol ʾăšer yiqrāʾûhû beʾĕmet</strong> — "the LORD is near to all who call on him, to all who call on him in sincerity/truth" — <em>qārôb</em> (near, Qal adjective from <em>qārab</em>, to draw near) — YHWH\'s nearness is the counter to his transcendence. The cosmic king (vv11-13) who governs all ages is also <em>qārôb</em> (near) to the individual who calls. <em>beʾĕmet</em> (in truth, sincerity, faithfulness) — the qualifier that the calling must be genuine. <em>ʾĕmet</em>-shaped prayer is prayer aligned with reality, not manipulation.</p>',
    "19": '<p><strong>rĕṣôn-yĕrēʾāyw yaʿăśeh wĕʾet-šawʿātām yišmaʿ wĕyôšîʿēm</strong> — "he fulfills the desire of those who fear him; he hears their cry and saves them" — <em>rĕṣôn-yĕrēʾāyw yaʿăśeh</em> (the desire of those who fear him he fulfills) — the same <em>rāṣôn</em> (desire) as v16 where all living things\' desires are satisfied; now the specific sub-community of the God-fearers receives particular attention. Fear of the LORD is the channel through which general divine goodness (vv9,16) flows specifically to those in relationship with him.</p>',
    "20": '<p><strong>šômēr yhwh ʾet-kol-ʾōhăbāyw wĕʾēt kol-hārĕšāʿîm yašmîd</strong> — "the LORD guards all who love him, but he will destroy all the wicked" — the final antithesis in the acrostic (missing only the nun verse). <em>ʾōhăbāyw</em> (those who love him) — love reciprocating love; the God who showed <em>ḥesed</em> is loved by those who experience it. <em>yašmîd</em> (will destroy, from <em>šāmad</em>, to annihilate, destroy completely) — the same fate as the enemies of Israel under the ban. The Psalter does not sentimentalize divine goodness: the open hand of v16 and the destroying word of v20 belong to the same God.</p>',
    "21": '<p><strong>tĕhillat yhwh yĕdabbēr-pî wîbārēk kol-bāśār šēm qodšô lĕʿôlām wāʿed</strong> — "my mouth will speak the praise of the LORD, and let all living flesh bless his holy name forever and ever" — the psalm closes by circling back to v1\'s individual pledge ("I will bless your name forever and ever") but expanding it to <em>kol-bāśār</em> (all flesh, all living creatures — the broadest possible biological category). The move from "I will exalt you" (v1) to "let all flesh bless" (v21) traces the psalm\'s theological arc: individual praise becomes universal praise. The acrostic that covers the whole Hebrew alphabet mirrors the universal scope of the praise content.</p>',
  },
  "146": {
    "1": '<p><strong>hallĕlû-yāh hallĕlî napšî ʾet-yhwh</strong> — "Praise the LORD! Praise the LORD, O my soul!" — Ps 146 opens the Hallelujah Quintet (Ps 146-150), each psalm beginning and ending with <em>hallĕlûyāh</em>. The self-address <em>hallĕlî napšî</em> (praise the LORD, O my soul) — the soul (<em>nepeš</em>) called to praise matches Ps 103:1-2 (same self-exhortation). The psalmist commands his own interior life to align with worship — the will engaging the emotions and the whole living self in the act of praise.</p>',
    "2": '<p><strong>ʾăhallĕlāh yhwh bĕḥayyāy ʾăzammĕrāh lĕʾĕlōhay bĕʿôdî</strong> — "I will praise the LORD all my life; I will sing praises to my God as long as I live" — <em>bĕḥayyāy</em> (while I live, in my life) + <em>bĕʿôdî</em> (as long as I exist, while I am yet) — the two temporal phrases expressing lifelong praise. This stands in deliberate contrast to vv3-4: human princes have no life beyond death (their plans perish), but the psalmist\'s praise extends to the full length of his life. The reliability of YHWH (v6-9) is the ground for a life of praise.</p>',
    "3": '<p><strong>ʾal-tibtĕḥû binnĕdîbîm bĕben-ʾādām šeʾên lô tĕšûʿāh</strong> — "do not put your trust in princes, in any human being, for there is no salvation in them" — <em>nĕdîbîm</em> (princes, nobles, willing/generous ones) — the highest rank of human power. <em>ben-ʾādām</em> (son of Adam, a human being) — the mortality-marker; humans are sons of Adam, subject to Adam\'s curse. <em>šeʾên lô tĕšûʿāh</em> (in whom there is no salvation/rescue) — <em>tĕšûʿāh</em> (salvation, deliverance, from <em>yāšaʿ</em>) — the same root as <em>yĕhôšûaʿ</em> (Joshua/Jesus). No human being, however powerful, has the capacity to save; <em>tĕšûʿāh</em> belongs only to YHWH (v7-9).</p>',
    "4": '<p><strong>tēṣēʾ rûḥô yāšub lĕʾadmātô bayyôm hahûʾ ʾābĕdû ʿešĕtōnōtāyw</strong> — "when his breath/spirit departs, he returns to his earth/soil; on that very day his plans come to nothing" — <em>tēṣēʾ rûḥô</em> (his spirit/breath departs) — <em>rûaḥ</em> as the animating breath; when it departs, the body becomes a corpse. <em>yāšub lĕʾadmātô</em> (he returns to his earth/soil) — the reverse of Gen 2:7 (YHWH breathed into the <em>ʾādām</em> made from <em>ʾadāmāh</em>); death is that creation reversed. <em>bayyôm hahûʾ ʾābĕdû ʿešĕtōnōtāyw</em> (on that very day his plans/thoughts perish) — <em>ʿĕšĕtōnôt</em> (plans, schemes, thoughts, from <em>ʿāšat</em>) — the most powerful person\'s best-laid plans evaporate the moment the breath leaves. This makes trust in princes not merely imprudent but structurally futile.</p>',
    "5": '<p><strong>ʾašrê šeʾēl yaʿăqōb bĕʿezrô śibrô ʿal-yhwh ʾĕlōhāyw</strong> — "blessed is the one whose help is the God of Jacob, whose hope is in the LORD his God" — <em>ʾašrê</em> (blessed, happy) — the beatitude form. In deliberate contrast to v3 (trust in princes = futile), v5 offers the alternative: help from the God of Jacob. <em>ʾēl yaʿăqōb</em> (the God of Jacob) — the patriarchal title emphasizing covenant continuity; Jacob\'s God is the God of the powerless-made-powerful, the wrestler, the schemer redeemed. <em>śibrô ʿal-yhwh</em> (whose hope is placed on the LORD) — <em>śābar</em> (to hope, wait, expect — same as Ps 145:15) — the posture of expectant trust.</p>',
    "6": '<p><strong>ʿōśeh šāmayim wāʾāreṣ ʾet-hayyām wĕʾet-kol-ʾăšer-bām haššōmēr ʾĕmet lĕʿôlām</strong> — "who made heaven and earth, the sea and everything in them, and who keeps faith forever" — the classic creator-title <em>ʿōśeh šāmayim wāʾāreṣ</em> (maker of heaven and earth) — appearing also in Ps 115:15; 121:2; 124:8 — grounds the help of v5 in creation sovereignty. The creator who made all things can rescue within what he made. <em>haššōmēr ʾĕmet lĕʿôlām</em> (the one who keeps faith forever) — <em>ʾĕmet</em> (truth, faithfulness, reliability) + <em>šāmar</em> (to keep, guard) — YHWH guards his own faithfulness; it is not something that can be violated or erode. Unlike the prince whose plans perish in a day (v4), YHWH\'s faithfulness is permanent.</p>',
    "7": '<p><strong>ʿōśeh mišpāṭ laʿăšûqîm nôtēn leḥem lārĕʿēbîm yhwh mattîr ʾăsûrîm</strong> — "who secures justice for the oppressed and gives food to the hungry; the LORD sets prisoners free" — three divine actions in one verse: <em>ʿōśeh mišpāṭ laʿăšûqîm</em> (doing justice for the oppressed) — <em>ʿāšaq</em> (to oppress, squeeze, defraud) — those who have been wronged in the legal and economic system. <em>nôtēn leḥem lārĕʿēbîm</em> (giving bread to the hungry) — the provision of basic sustenance as a divine act. <em>yhwh mattîr ʾăsûrîm</em> (the LORD sets free those who are bound) — <em>āsar</em> (to bind, imprison). The six divine actions for the vulnerable in vv7-9 form the basis for Jesus\' Nazareth manifesto (Luke 4:18-19) and the beatitudes (Matt 5:3-12) — liberation of precisely these categories of people signals the arrival of the kingdom.</p>',
    "8": '<p><strong>yhwh pōqēaḥ ʿiwwĕrîm yhwh zōqēp kĕpûpîm yhwh ʾōhēb ṣaddîqîm</strong> — "the LORD gives sight to the blind; the LORD lifts up those who are bowed down; the LORD loves the righteous" — <em>pōqēaḥ ʿiwwĕrîm</em> (opening [the eyes of] the blind, from <em>pāqaḥ</em>, to open eyes, ears) — the opening of eyes as divine work (Isa 35:5; 42:7). Jesus\' healing of the blind (Matt 11:5; John 9) is presented as fulfillment of this prophetic-psalmic pattern. <em>yhwh zōqēp kĕpûpîm</em> (the LORD lifts up those who are bowed down) — same as Ps 145:14 (<em>zôqēp kĕpûpîm</em>), making the connection explicit. <em>yhwh ʾōhēb ṣaddîqîm</em> (the LORD loves the righteous) — the love of YHWH is not merely obligatory covenant action but genuine <em>ʾahăbāh</em> (love).</p>',
    "9": '<p><strong>yhwh šōmēr ʾet-gērîm yātôm wĕʾalmānāh yĕʿôdēd wĕderek rĕšāʿîm yĕʿawwēt</strong> — "the LORD watches over the alien resident; he supports the fatherless and the widow; but the way of the wicked he overturns/makes crooked" — the three classic vulnerable categories: <em>gēr</em> (alien/stranger resident, one without full civic rights), <em>yātôm</em> (orphan, the fatherless), and <em>ʾalmānāh</em> (widow) — the legal-social triad of those without a male protector, repeatedly named in Torah (Exod 22:21-22; Deut 27:19). <em>yĕʿôdēd</em> (he supports, sustains, from <em>ʿûd</em>, to support, restore) — YHWH as the structural support replacing the missing human protector. <em>wĕderek rĕšāʿîm yĕʿawwēt</em> (the way of the wicked he overturns/makes crooked) — the ironic use of <em>ʿāwah</em> (to twist, bend, pervert — used of injustice): the God who straightens the crooked paths of the poor perverts the plans of the wicked.</p>',
    "10": '<p><strong>yimlōk yhwh lĕʿôlām ʾĕlōhayik ṣiyyôn lĕdōr wādōr hallĕlû-yāh</strong> — "the LORD will reign forever — your God, O Zion, for all generations. Praise the LORD!" — <em>yimlōk yhwh lĕʿôlām</em> (the LORD will reign forever) — the eternal kingship declaration closes the psalm: unlike the prince of v3 whose plans die with his breath, YHWH\'s reign has no term. <em>ʾĕlōhayik ṣiyyôn</em> (your God, O Zion) — the universal sovereign is specifically Zion\'s covenant God; the cosmic and the particular are held together. <em>hallĕlû-yāh</em> — closing the first of the Quintet and opening the path to Pss 147-150, the great doxological finale of the entire Psalter.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 140-146 mkt-original written.')

if __name__ == '__main__':
    main()
